1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteResult {
13	  premium: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	// Rounds up in MHPCO's favor, guarding against floating-point drift
25	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
26	const roundUpInFavor = (amount: number): number =>
27	  Math.ceil(Number(amount.toFixed(6)));
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const COMPONENT_BASE_PREMIUM = 25;
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE_PREMIUM = 60;
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	// A same-type group of exactly BLOCK_SIZE components forms one block priced at
37	// BLOCK_BASE_PREMIUM; any other count is priced per component. (Multi-block and
38	// block-plus-leftover pricing are not yet implemented.)
39	const componentGroupBasePremium = (count: number): number =>
40	  count === BLOCK_SIZE
41	    ? BLOCK_BASE_PREMIUM
42	    : count * COMPONENT_BASE_PREMIUM;
43	
44	const itemBasePremium = (item: Item): number =>
45	  isComponent(item) ? COMPONENT_BASE_PREMIUM : BASE_PREMIUMS[item.type];
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
49	const HIGH_ENCHANTMENT_THRESHOLD = 5;
50	const FIRST_INSURANCE_RATE = 0.1;
51	const LOYALTY_DISCOUNT_RATE = 0.2;
52	const LOYALTY_YEARS_THRESHOLD = 2;
53	const FOLLOWUP_DISCOUNT_RATE = 0.15;
54	
55	// A surcharge term contributes `rate * base` when its condition holds, else 0.
56	const surchargeWhen = (applies: boolean, rate: number, base: number): number =>
57	  applies ? rate * base : 0;
58	
59	const itemSurcharge = (item: Item): number => {
60	  const base = itemBasePremium(item);
61	  const curse = surchargeWhen(item.cursed ?? false, CURSE_SURCHARGE_RATE, base);
62	  const highEnchantment = surchargeWhen(
63	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
64	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
65	    base,
66	  );
67	  return curse + highEnchantment;
68	};
69	
70	const countByType = (items: Item[]): Record<string, number> =>
71	  items.reduce<Record<string, number>>((counts, item) => {
72	    counts[item.type] = (counts[item.type] ?? 0) + 1;
73	    return counts;
74	  }, {});
75	
76	const sum = (values: number[]): number =>
77	  values.reduce((running, value) => running + value, 0);
78	
79	const basePremiumTotal = (items: Item[]): number => {
80	  const mainItems = items.filter((item) => !isComponent(item));
81	  const components = items.filter(isComponent);
82	
83	  const mainItemsTotal = sum(mainItems.map(itemBasePremium));
84	  const componentsTotal = sum(
85	    Object.values(countByType(components)).map(componentGroupBasePremium),
86	  );
87	
88	  return mainItemsTotal + componentsTotal;
89	};
90	
91	// Net policy-level adjustment derived from the policy base: the first-insurance
92	// surcharge (always) minus the loyalty discount (for established customers) and
93	// the follow-up discount (for contracts after the customer's first quote).
94	const policyBaseModifiers = (
95	  customer: Customer,
96	  policyBase: number,
97	  followUp: boolean,
98	): number => {
99	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
100	  const loyaltyDiscount =
101	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
102	      ? policyBase * LOYALTY_DISCOUNT_RATE
103	      : 0;
104	  const followUpDiscount = followUp ? policyBase * FOLLOWUP_DISCOUNT_RATE : 0;
105	  return firstInsurance - loyaltyDiscount - followUpDiscount;
106	};
107	
108	export interface QuoteOptions {
109	  followUp?: boolean;
110	}
111	
112	export const quote = (
113	  customer: Customer,
114	  items: Item[],
115	  options: QuoteOptions = {},
116	): QuoteResult => {
117	  const policyBase = basePremiumTotal(items);
118	  const surcharges = sum(items.map(itemSurcharge));
119	  const exactPremium =
120	    policyBase +
121	    surcharges +
122	    policyBaseModifiers(customer, policyBase, options.followUp ?? false) +
123	    PROCESSING_FEE;
124	  return { premium: roundUpInFavor(exactPremium) };
125	};
126	
127	export const claim = (...args: unknown[]): unknown => {
128	  return undefined;
129	};
